// Função que calcula a próxima posição da roleta
function proximaRodada(atual, total) {
  if (!total || total <= 0) {
    throw new Error("num_sdrs precisa ser maior que zero");
  }

  if (!atual || atual < 1) {
    return 1;
  }

  return atual >= total ? 1 : atual + 1;
}

// Lê os valores do input
const total = input.num_sdrs;
const atual = input.roleta_vez;

// Calcula próximo número
const proximo = proximaRodada(atual, total);

// Retorna resultado
return [
  {
    json: {         // mantém os dados anteriores
      roleta: proximo // atualiza a roleta
    }
  }
];

