const resumo = $('When Executed by Another Workflow').first().json.resumo ?? '';

// Extrai só o valor depois de "Tópico do transbordo:" ignorando qualquer coisa entre parênteses
const match = resumo.match(/T[oó]pico do transbordo[^:]*:\s*([^\n(]+)/i);
const topico_raw = match ? match[1].trim() : '';

// Normaliza o raw para comparação
const t = topico_raw
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .trim();

// Mapa fechado — só aceita esses 8 valores
const TOPICOS_VALIDOS = [
  { key: 'remarcacao_agendamento', termos: ['remarca', 'reagend'] },
  { key: 'erro_agendamento',       termos: ['erro em agendamento', 'erro no agendamento'] },
  { key: 'agendamento',            termos: ['agendamento'] },
  { key: 'parcerias',              termos: ['parceria', 'parcerias'] },
  { key: 'suporte',                termos: ['suporte'] },
  { key: 'duvidas',                termos: ['duvida', 'duvidas'] },
  { key: 'pediu_humano',           termos: ['pediu humano', 'pediu atendimento humano'] },
  { key: 'outros',                 termos: ['outros', 'other'] },
];

const topico_normalizado = TOPICOS_VALIDOS.find(({ termos }) =>
  termos.some(termo => t.startsWith(termo) || t === termo)
)?.key ?? 'outros'; // fallback sempre vai para 'outros', nunca inventa

return [{
  json: {
    topico_raw,
    topico_normalizado
  }
}];

